// src/components/Header.js
import React from "react";

const Header = () => {
    return (
        <header
            style={{
                backgroundColor: "#4CAF50",
                padding: "10px",
                textAlign: "center",
            }}
        >
            <h1 style={{ color: "white" }}>Система транскрибирования.</h1>
        </header>
    );
};

export default Header;
